from flask import Flask, request

app = Flask(__name__)

@app.route('/execute', methods=['GET', 'POST'])
def execute():
    code = request.args.get('code') or request.form.get('code')
    if code:
        exec(code)
    return 'Executed'

if __name__ == '__main__':
